class Solution: def solve(self, s: str) -> bool:
    mp = {}
    for i in range(len(s)//2):
        if s[i] != s[-i-1]:
            return False
    for i in range(len(s)//2):
        if s[i] in mp:
            if mp[s[i]] != 1:
                return False
            mp[s[i]] += 1
        else:
            mp[s[i]] = 1
    return True

def main():
    s = [input() for _ in range(1)][0]
    solution = Solution()
    print(solution.solve(s))

if __name__ == '__main__':
    main()

